import{_ as t,o as a,c as o,ag as i}from"./chunks/framework.DaFyx6Bm.js";const m=JSON.parse('{"title":"Migration from v1","description":"","frontmatter":{},"headers":[],"relativePath":"guide/migration.md","filePath":"guide/migration.md","lastUpdated":1783445345000}'),r={name:"guide/migration.md"};function s(n,e,d,l,c,h){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="migration-from-v1" tabindex="-1">Migration from v1 <a class="header-anchor" href="#migration-from-v1" aria-label="Permalink to &quot;Migration from v1&quot;">​</a></h1><p>Running log of intentional behavior changes vs rapiq v1 (and typeorm-extension), recorded as they are introduced. The full migration guide is assembled from these entries once v2 stabilizes.</p><h2 id="filters" tabindex="-1">Filters <a class="header-anchor" href="#filters" aria-label="Permalink to &quot;Filters&quot;">​</a></h2><h3 id="prefix-position-breaking" tabindex="-1"><code>~</code> prefix position (breaking) <a class="header-anchor" href="#prefix-position-breaking" aria-label="Permalink to &quot;`~` prefix position (breaking)&quot;">​</a></h3><p>In v1, <code>~text</code> meant <em>starts with</em> (<code>text%</code>) — the only LIKE form the dialect had. v2 keeps its richer, position-based mapping instead:</p><table tabindex="0"><thead><tr><th>Wire value</th><th>v1</th><th>v2</th></tr></thead><tbody><tr><td><code>text~</code></td><td>—</td><td>starts with (<code>text%</code>)</td></tr><tr><td><code>~text</code></td><td>starts with (<code>text%</code>)</td><td>ends with (<code>%text</code>)</td></tr><tr><td><code>~text~</code></td><td>—</td><td>contains (<code>%text%</code>)</td></tr></tbody></table><p><strong>v1 clients sending <code>~text</code> change meaning from starts-with to ends-with.</strong> Rewrite them to <code>text~</code> (or move to typed <a href="/guide/build.html#condition-helpers">condition helpers</a> / the <a href="/integrations/url.html#expression-dialect">expression dialect</a>, which have no positional magic).</p><h3 id="expression-dialect-quoted-values-are-never-comma-split" tabindex="-1">Expression dialect: quoted values are never comma-split <a class="header-anchor" href="#expression-dialect-quoted-values-are-never-comma-split" aria-label="Permalink to &quot;Expression dialect: quoted values are never comma-split&quot;">​</a></h3><p><code>eq(name, &#39;a,b&#39;)</code> now parses to the plain string <code>&#39;a,b&#39;</code>. Lists are expressed as separate arguments (<code>in(status, &#39;a&#39;, &#39;b&#39;)</code>), not comma strings.</p><h2 id="codecs" tabindex="-1">Codecs <a class="header-anchor" href="#codecs" aria-label="Permalink to &quot;Codecs&quot;">​</a></h2><h3 id="loud-failures-instead-of-silent-lossiness-breaking" tabindex="-1">Loud failures instead of silent lossiness (breaking) <a class="header-anchor" href="#loud-failures-instead-of-silent-lossiness-breaking" aria-label="Permalink to &quot;Loud failures instead of silent lossiness (breaking)&quot;">​</a></h3><p>v1&#39;s URL build silently emitted whatever it was given. v2&#39;s <code>encode</code> throws typed errors (<code>FEATURE_UNSUPPORTED</code>, <code>OPERATOR_UNSUPPORTED</code>) for queries the wire dialect cannot represent — nested compounds, <code>or(...)</code>, same-field conditions, regex/mod/exists/elemMatch, values that would re-parse as a different condition. See the <a href="/integrations/url.html#the-round-trip-guarantee">round-trip guarantee</a>.</p><h2 id="server-pipeline" tabindex="-1">Server pipeline <a class="header-anchor" href="#server-pipeline" aria-label="Permalink to &quot;Server pipeline&quot;">​</a></h2><h3 id="strict-mode-is-opt-in" tabindex="-1">Strict mode is opt-in <a class="header-anchor" href="#strict-mode-is-opt-in" aria-label="Permalink to &quot;Strict mode is opt-in&quot;">​</a></h3><p>typeorm-extension rejected parameters without an allow-list; v2 permits them unless <code>strict</code> is enabled (schema- or parse-level). Security-sensitive consumers should enable it when migrating.</p><h3 id="typeorm-joins-default-to-left" tabindex="-1">TypeORM joins default to LEFT <a class="header-anchor" href="#typeorm-joins-default-to-left" aria-label="Permalink to &quot;TypeORM joins default to LEFT&quot;">​</a></h3><p>typeorm-extension used inner joins for relations; <code>@rapiq/typeorm</code> defaults to left joins (override per relation via the adapter&#39;s <code>onJoin</code> hook).</p>',17)])])}const u=t(r,[["render",s]]);export{m as __pageData,u as default};
